from flask import Flask, request, redirect, url_for
from flask_mail import Mail, Message
import secrets

app = Flask(__name__)

# Mail setup
app.config['MAIL_SERVER']='your_mail_server'
app.config['MAIL_PORT'] = 465
app.config['MAIL_USERNAME'] = 'your@mail.com'
app.config['MAIL_PASSWORD'] = 'password'
app.config['MAIL_USE_TLS'] = False
app.config['MAIL_USE_SSL'] = True
mail = Mail(app)

users = {}

def send_reset_link(email):
    reset_token = secrets.token_urlsafe(16)
    msg = Message('MFA Reset Link',
                  sender="noreply@your-email.com",
                  recipients=[email])
    reset_link = url_for('reset_mfa', token=reset_token, _external=True)
    msg.body = f'Click this link to reset your MFA settings: {reset_link}'
    users[email]['reset_token'] = reset_token
    mail.send(msg)

@app.route('/enable_mfa', methods=['POST'])
def enable_mfa():
    email = request.form.get('email')
    users[email] = {'mfa': True}
    return 'MFA enabled.', 200

@app.route('/disable_mfa', methods=['POST'])
def disable_mfa():
    email = request.form.get('email')
    users[email] = {'mfa': False}
    return 'MFA disabled.', 200

@app.route('/reset-mfa', methods=['POST'])
def request_reset_mfa():
    email = request.form.get('email')
    if email in users:
        send_reset_link(email)
        return 'Reset link sent.', 200
    else:
        return 'Email not found.', 404

@app.route('/reset-mfa/<token>', methods=['GET'])
def reset_mfa(token):
    for user in users:
        if 'reset_token' in users[user] and users[user]['reset_token'] == token:
            users[user]['mfa'] = False
            return redirect(url_for('login'))
    return 'Invalid token.', 404

